function LGameTable:ClearTable(k)
	local key = self._caches[k]
	self._caches[k] = nil
	self._tables[k] = nil
	GameTable[k] = nil
	if key then
		package.loaded[key] = nil
		package.preload[key] = nil
	end
end

function LGameTable:ClearAllTable()
	local tables = self._tables
	if tables then
		for k,v in pairs(tables) do
			self:ClearTable(k)
		end
	end
end

function LGameTable:ClearSensitiveCache()
	local data = self._sensitiveCache
	if not data then return end
	self._sensitiveCache = nil
	local conf = GameTable
	for k,v in pairs(data) do
		conf[v] = nil
	end
end

function LGameTable:SetSensitive(bSensitive)
	local oldSensitive = self._isSensitive
	if bSensitive == oldSensitive then return end
	self._isSensitive = bSensitive
	self._isNeedUpdateSensitive = true
	gLGameLanguage:SetSensitive(bSensitive)
end

function LGameTable:ClearNeedUpdateSensitive()
	self._isNeedUpdateSensitive = false
end

function LGameTable:IsSensitive()
	return self._isSensitive
end

function LGameTable:IsNeedUpdateSensitive()
	return self._isNeedUpdateSensitive
