function LGameTable:GetTable(k)
	local realPath = nil
	local isIosPath = false
	--优先提审屏蔽
	if PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
		if gLGameLanguage:VerifyIos(k) then
			realPath = gLGameLanguage:GetIosPath(k)
			isIosPath = true
		end
	end

	--其次和谐屏蔽
	if not isIosPath and self._isSensitive then
		local newk = gLGameLanguage:GetSensitiveTableName(k)
		if newk ~= k then
			if not self._sensitiveCache then
				self._sensitiveCache = {}
			end
			self._sensitiveCache[newk] = k
			k = newk
		end
	end

	if self._caches[k] then
		return self._tables[k]
	end

	if not isIosPath then
		realPath = gLGameLanguage:GetConfPath(k)
	end
	local data = LxRequireWithoutReload(realPath)
	self._tables[k] = data
	self._caches[k] = realPath
	return data
end

--发现是提审版本的时候清除之前的配置
function LGameTable:ClearBeforeConf()
	local _caches = self._caches
	local _tables = self._tables
	local conf = GameTable
	for k,v in pairs(_caches) do
		local moduleFullName = v
		moduleFullName = string.gsub(moduleFullName, "_ios", "")
		package.loaded[moduleFullName] = nil
		package.preload[moduleFullName] = nil
		_caches[k] = nil
		_tables[k] = nil
		conf[k] = nil
	end
end


return LGameTable


